import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"诗剑：人间正道","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/诗剑/诗剑：人间正道.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/诗剑/诗剑：人间正道.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/诗剑/诗剑：人间正道.md"};function o(d,e,_,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"诗剑-人间正道",tabindex:"-1"},[p("诗剑：人间正道 "),r("a",{class:"header-anchor",href:"#诗剑-人间正道","aria-label":'Permalink to "诗剑：人间正道"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌036")])])],-1),n('<h1 id="诗剑-人间正道-1" tabindex="-1">诗剑：人间正道 <a class="header-anchor" href="#诗剑-人间正道-1" aria-label="Permalink to &quot;诗剑：人间正道&quot;">​</a></h1><p>诗剑：人间正道</p><p>天若有情天亦老，人间正道是沧桑。</p><p>人间正道是逐升武器，必须要持有“百世诗篇”训练才能够兑换。人间正道是一柄“诗剑”。人间正道的武器等级无法高于你的百世诗篇训练等级。（例如你只拥有C级的“百世诗篇”训练，则你无法兑换B级别的夜阑碧光。）</p><p>如无特殊说明，则下属的武器各级之间的特性均为继承关系而非替换。</p><p>D级<br> 价格：D+500<br> 描述：你看向手中才气所聚成的长剑，只见这柄长剑看起来平平无奇，没有精美的装饰，像是村镇铁匠所打造出来的器具。你不禁怀疑，这真是蕴含了诗魂神妙的诗剑吗？你把才气注入其中，这柄普通的剑，散发出星星点点的火焰，似乎告诉着你，它所蕴含的力量。<br> 人间正道是一柄具有6L武器伤害的轻剑。具有如下特性：<br> 【虎踞】：<br> “独坐池塘如虎踞，绿荫树下养精神。”<br> “春来我不先开口，哪个虫儿敢作声？”<br> 虎踞需要你消耗一个移动动作和2点才气，以人间正道进行一次白刃格挡才可以发动。<br> 在进行了这次格挡防御之后，你可以标准动作宣言准备一次攻击。在这一轮内，如果其他角色对你或者你的队友进行了攻击，则你可以在回合外立刻打断性地插入一次攻击，这次攻击额外具有1点攻击上的附加成功。</p><p>C级<br> 价格：C+1000<br> 描述：你以诗心将人间正道淬炼。这柄剑并没有变得华贵，虽然你能够看到剑上缠绕着更多星火，但是剑的本身，却更加的沉稳，内敛，甚至多了些久经战阵的痕迹。<br> 你用着这这柄剑，去斩杀那些吃人的魍魉。你用着这柄剑，去保护诗界之中黎庶的安危。<br> 你见了这诗界之中世态的炎凉。<br> 人人皆言，得诗心者，以斩魍魉，护众生为己任。<br> 可一旦超然的地位存在，就算是外魔邪念不得入心，人心自己的狭隘却会将人吞噬。<br> 一柄剑可以斩杀魍魉，但一柄剑可除得尽自私，卑劣？<br> 在本级，人间正道的武器伤害提升到14L。具有以下特性：<br> 【虎踞·贰】：现在，你在发动虎踞时，可以将消耗的才气提升到6点。这会令你以虎踞的效果在回合外发动攻击时，额外具有B级别的免疫先制的效果。并且你在进行这次攻击时，在D级的基础上，在额外具有2dp的攻击上的速度加值和1点附加成功。<br> 【风扫寰宇】：“要似昆仑崩绝壁，又恰像台风扫寰宇。”<br> 你挥动人间正道之时，长风自起，要将一切腐朽邪恶的东西一扫而空。<br> 现在，你以人间正道进行攻击时，可以对前方6米直线范围内的所有敌人为目标。</p><p>B级<br> 价格：B+2000<br> 描述：苦思良久，你在黑暗的世界里，决心举起一盏火炬。<br> 你将书院世家视如珍宝的诗道之途分与众人，你让更多人能够自食其力。<br> 众人拾柴，火可燎原。一步一步地，你们驱去魍魉。<br> 你对着追随你的人讲：“站起来，不许跪。”<br> 在本级，人间正道的武器伤害提升到21L。具有以下特性：<br> 【风扫寰宇·贰】：现在，你以人间正道进行攻击时，改为以30米范围的圆形范围内的所有敌人为目标，并且受到影响的所有敌人需要以反射豁免来进行豁免。<br> 【缚苍龙】：“今日长缨在手，何时缚住苍龙？”<br> 手持人间正道，剑上星火翻涌，赤光流转，你挥剑而出，剑势带着磅礴的人道之力，将一切危害黎庶安宁的凶蛟恶龙统统困锁。<br> 消耗一个整轮动作和10点才气，你可以施展缚苍龙。缚苍龙是一次诗剑攻击，这次诗剑攻击的出目将会变为1.5倍，并且附带等额的纠缠点数，这一纠缠点数改为由意志豁免进行豁免。<br> 同时只要这一次攻击切实造成了伤害，则剑上星火还会沿着困锁敌人的长缨而上，在敌人身上成燎原之势。你这次攻击还附带等额的燃烧点数。</p><p>A级<br> 价格：A+4000<br> 描述：至此，人间正道已经褪去剑形，化作一团明亮的火光，被握在你的手中，一个个凝聚着不屈意志与美好希望的微小星火，铸就了这柄斩去一切丑恶，重整山河，再造乾坤的无上神锋。<br> 在本级，人间正道的武器伤害提升到33L，并且现在进行攻击时额外具有2点附加成功。同时，人间正道具有以下特性。<br> 【登攀】：“世上无难事，只要肯登攀。”<br> 不等他人救世，不信什么皇帝神明，纵然天倾地裂，亦奋斗到底，重造他个清平人间。<br> 执此剑者，不信宿命，不怕那些个强加在自己以及同道之人身上的歪理邪说，只管挺身而战。从现在开始，只要你手持人间正道，你具有A级别的针对命运来源效果的免疫。<br> 【诗魂】：现在，你能够召唤出剑中诗魂，与你并肩作战。<br> 然而人间正道的诗魂与其他诗魂并不相通。他并不情愿把自己塑造成后来者膜拜的神像。他教你放手去干，世界现在是属于你们的。<br> 在持有A级人间正道的前提下，你所获得的8点AP改为常驻拥有。<br> 由于显现诗魂是与剑中所留存的真灵进行共鸣，因而在违背真灵意愿的情况下，真灵将不会出手帮助你，这将会令你无法发动该诗魂的能力，并且失去A级训练中诗魂所提供的8AP。对于人间正道中的诗魂来说，如果你背离了守护黎庶、追求公道的初心，或试图凌驾于众生之上成为新的压迫者，则他将放弃帮助你。<br> 你先前从人间正道获得的特性产生如下变化：<br> 【虎踞】特性现在进化为【虎踞龙盘】。<br> 【虎踞龙盘】：“虎踞龙盘今胜昔，天翻地覆慨而慷。”<br> 在继承【虎踞】和【虎踞·贰】的所有效果的基础上，现在，你发动【虎踞】时，可以将投入的才气再提升2点，令C级追加获得的免疫先制能力上升到A级。并且由于现在你的剑中蕴含了新必胜旧的变革真意，你现在每发动一次虎踞，则你下一次发动虎踞时在攻击上获得的速度加值提升4点，附加成功提升1点。你最多反复获得这一效果的次数等同于你的传奇决心。<br> 现在，【风扫寰宇】改为令你在以人间正道进行攻击时，以270米圆形范围内的所有对象为目标，并且目标需要以反射豁免来应对攻击。<br> 现在，【缚苍龙】对敌人造成的纠缠点数和燃烧点数均提升为四档异常点数。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const A=a(s,[["render",o]]);export{f as __pageData,A as default};
